import requests

def test_audit_log_boundary_org_transition_returns_403():
    token = <get_privacy_officer_token_for_org>('ORG-A')
    headers = {'Authorization': f'Bearer {token}'}
    url = 'http://localhost:8080/AuditEvent'
    params = {'_organization': 'ORG-A-1'}

    resp = requests.get(url, headers=headers, params=params)

    assert resp.status_code == 403
    body = resp.json()
    assert len(body.get('entry', [])) == 0

import requests

def test_audit_log_missing_org_param_uses_token_scope():
    token = <get_privacy_officer_token_for_org>('ORG-A')
    headers = {'Authorization': f'Bearer {token}'}
    url = 'http://localhost:8080/AuditEvent'

    resp = requests.get(url, headers=headers)

    assert resp.status_code == 200
    body = resp.json()
    for entry in body.get('entry', []):
        assert 'ORG-A' in str(entry['resource'])
